class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        chosen = []
        total = 0
        num = 1
        while len(chosen) < n:
            conflict = False
            for v in chosen:
                if v + num == k:
                    conflict = True
                    break
            if not conflict:
                chosen.append(num)
                total += num
            num += 1
        return total

