class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        chosen = set()
        total = 0
        num = 1
        while len(chosen) < n:
            if (k - num) not in chosen:
                chosen.add(num)
                total += num
            num += 1
        return total

