var minimumSum = function(n, k) {
    const chosen = new Set();
    let total = 0;
    let num = 1;
    while (chosen.size < n) {
        if (!chosen.has(k - num)) {
            chosen.add(num);
            total += num;
        }
        num += 1;
    }
    return total;
};
